                <script>
        // Загрузка достижений
        fetch('/Achievement/GetEarned')
            .then(response => response.json())
            .then(achievements => {
                const container = document.getElementById('achievementsList');

                if (achievements.length === 0) {
                    container.innerHTML = '<p class=""text-muted"">Пока нет достижений. Играй и получай награды! 🌟</p>';
                    return;
                }

                achievements.forEach(ach => {
                    const card = document.createElement('div');
                    card.className = 'achievement-card';
                    card.innerHTML = `
                        <div class=""achievement-icon"">
                            <img src=""${ach.iconUrl}"" alt=""${ach.title}"">
                        </div>
                        <div class=""achievement-info"">
                            <h4>${ach.title}</h4>
                            <p>${ach.description}</p>
");
                WriteLiteral(@"                            <small>Получено: ${new Date(ach.earnedDate).toLocaleDateString()}</small>
                        </div>
                    `;
                    container.appendChild(card);
                });
            });
                </script>
            ");
